const student = $input.item.json;
const text = (student['submission Text'] || '').toLowerCase().trim();
const name = student['student Name'] || 'Unknown';
const id = student['student Id'] || 'N/A';

// Get all items from the input (this works reliably)
const allSubmissions = $input.all();

// Simple similarity check function
function calculateSimilarity(text1, text2) {
  if (!text1 || !text2) return 0;

  // Normalize texts
  const normalize = (t) => t.toLowerCase().replace(/\s+/g, ' ').trim();
  const t1 = normalize(text1);
  const t2 = normalize(text2);

  // If texts are identical or nearly identical
  if (t1 === t2) return 100;

  // Calculate word overlap
  const words1 = t1.split(' ');
  const words2 = t2.split(' ');
  const set1 = new Set(words1);
  const set2 = new Set(words2);

  const intersection = [...set1].filter(word => set2.has(word)).length;
  const union = new Set([...set1, ...set2]).size;

  const similarity = (intersection / union) * 100;
  return Math.round(similarity);
}

// Check against all previous submissions in this batch
let plagiarismFlag = false;
let matchedStudent = '';
let matchPercentage = 0;

for (const prevItem of allSubmissions) {
  const prevStudent = prevItem.json;
  const prevText = (prevStudent['submission Text'] || '').toLowerCase().trim();
  const prevName = prevStudent['student Name'] || 'Unknown';
  const prevId = prevStudent['student Id'] || 'N/A';

  // Don't compare with itself
  if (prevId === id && prevName === name) continue;

  const similarity = calculateSimilarity(text, prevText);

  // Flag if >80% similar (adjust threshold as needed)
  if (similarity > 80) {
    plagiarismFlag = true;
    matchedStudent = `${prevName} (${prevId})`;
    matchPercentage = similarity;
    console.log(`⚠️ PLAGIARISM: ${name} matches ${prevName} at ${similarity}%`);
    break;
  }
}

// Pass through with plagiarism info
return {
  json: {
    ...student,
    _plagiarism_detected: plagiarismFlag,
    _matched_with: matchedStudent,
    _similarity_percentage: matchPercentage
  }
};

